    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

// ===========================================
// /defer — Interactive Quest Deferral with Warning
// ===========================================
// Phase 1 (no target): List today's To-Do/In Progress quests
// Phase 2 (with target): Move selected quests to Deferred state,
//   increment defer_count, warn if defer_count >= threshold

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  state_deferred: $env.PULSE_STATE_DEFERRED_ID,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';
const DRY_RUN = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || 'false') === '1';

const DEFER_WARNING_THRESHOLD = 3;

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPatch = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'PATCH', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&apos;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

const updateMetaInHtml = (html, updates) => {
  if (!html) return html;
  const meta = extractMeta(html);
  if (!meta) return html;
  const updated = { ...meta, ...updates };
  const json = JSON.stringify(updated, null, 2);

  // Pattern 2: HTML with class attribute
  let result = html.replace(/<pre><code\s+class="language-pulse-meta">[\s\S]*?<\/code><\/pre>/, `<pre><code class="language-pulse-meta">${json}</code></pre>`);
  if (result !== html) return result;

  // Pattern 3: HTML without class (fallback)
  result = html.replace(/<pre><code>[\s\S]*?<\/code><\/pre>/, `<pre><code class="language-pulse-meta">${json}</code></pre>`);
  if (result !== html) return result;

  // Pattern 1: Markdown fenced code block
  result = html.replace(/```pulse-meta\s*\n[\s\S]*?\n\s*```/, `\`\`\`pulse-meta\n${json}\n\`\`\``);
  if (result !== html) return result;

  return html;
};

const PRIORITY_EMOJI = { 4: '\uD83D\uDD34', 3: '\uD83D\uDFE0', 2: '\uD83D\uDFE1', 1: '\uD83D\uDFE2', 0: '\uD83D\uDFE2' };
const PRIORITY_NAME = { 4: 'urgent', 3: 'high', 2: 'medium', 1: 'low', 0: 'none' };
const formatDuration = (min) => {
  if (!min) return '';
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

const target = $input.first().json.target;

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const projId = config.daily_quest_project_id;

  if (!target) {
    // Phase 1: List quests available for deferral
    const result = await withRetry(
      () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
      'Fetch today quests'
    );
    const allQuests = result.results || result || [];
    const actionable = allQuests.filter(q => {
      const sn = q.state_detail?.name;
      return sn === 'To-Do' || sn === 'In Progress';
    });

    if (actionable.length === 0) {
      return [{ json: {
        response_type: 'info',
        message: '\u2139\uFE0F No quests available to defer.',
        data: null, suggestions: ['Try /today to view your quest board'], awaiting_input: false
      }}];
    }

    let list = '';
    for (let i = 0; i < actionable.length; i++) {
      const q = actionable[i];
      const pEmoji = PRIORITY_EMOJI[q.priority] || '\uD83D\uDFE1';
      const pName = PRIORITY_NAME[q.priority] || 'medium';
      const meta = extractMeta(q.description_html);
      const time = meta?.routine_time || '--:--';
      const dur = meta?.routine_duration_min ? formatDuration(meta.routine_duration_min) : '';
      const deferCount = meta?.defer_count || 0;
      const deferSuffix = deferCount > 0 ? ` (deferred x${deferCount})` : '';
      list += `${i + 1}. [${pEmoji} ${pName}] ${q.name} \u2014 ${time}${dur ? ` (${dur})` : ''}${deferSuffix}\n`;
    }

    return [{ json: {
      response_type: 'list',
      message: list,
      data: { quest_ids: actionable.map(q => q.id), count: actionable.length },
      suggestions: ['Enter number(s) (e.g., 1,3 or 1-3):'],
      awaiting_input: true
    }}];
  }

  // Phase 2: Defer selected quests
  const issueIds = target.split(',').map(s => s.trim()).filter(Boolean);
  const nowStr = new Date().toLocaleTimeString('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit' });

  // Validate issue IDs belong to today's actionable quests
  const todayResult = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today quests for validation'
  );
  const todayQuests = todayResult.results || todayResult || [];
  const actionableIds = new Set(
    todayQuests.filter(q => {
      const sn = q.state_detail?.name;
      return sn === 'To-Do' || sn === 'In Progress';
    }).map(q => q.id)
  );

  const invalidIds = issueIds.filter(id => !actionableIds.has(id));
  if (invalidIds.length > 0) {
    return [{ json: {
      response_type: 'error',
      message: `\u274C [INVALID_INPUT] Issue(s) ${invalidIds.join(', ')} are not in today's actionable quests.`,
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Use /defer to see available quests'],
      awaiting_input: false
    }}];
  }

  let deferred = 0;
  const warnings = [];

  for (const issueId of issueIds) {
    // Fetch current issue to get description and defer_count
    const issue = await withRetry(
      () => apiGet(`/projects/${projId}/issues/${issueId}/?expand=labels,state`),
      `Fetch issue ${issueId}`
    );

    const meta = extractMeta(issue.description_html);
    const currentCount = meta?.defer_count || 0;
    const newCount = currentCount + 1;

    // Update defer_count in description
    const updatedHtml = updateMetaInHtml(issue.description_html, { defer_count: newCount });

    if (DRY_RUN) {
      console.log(`[DRY_RUN] Would defer issue ${issueId} (state → Deferred, defer_count: ${newCount})`);
      console.log(`[DRY_RUN] Would add comment on issue ${issueId}`);
    } else {
      // Move to Deferred state and update description
      await withRetry(
        () => apiPatch(`/projects/${projId}/issues/${issueId}/`, {
          state: config.state_deferred,
          description_html: updatedHtml
        }),
        `Defer issue ${issueId}`
      );

      // Add comment
      await withRetry(
        () => apiPost(`/projects/${projId}/issues/${issueId}/comments/`, {
          comment_html: `<p>\u23F8\uFE0F [${nowStr}] Deferred by user (count: ${newCount})</p>`
        }),
        `Comment on ${issueId}`
      );
    }

    if (newCount >= DEFER_WARNING_THRESHOLD) {
      warnings.push(`\u26A0\uFE0F "${issue.name}" has been deferred ${newCount} times. Consider removing it.`);
    }

    deferred++;
  }

  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  let message = `\u23F8\uFE0F${dryTag} ${deferred} quest${deferred !== 1 ? 's' : ''} deferred.`;
  if (warnings.length > 0) {
    message += '\n\n' + warnings.join('\n');
  }

  return [{ json: {
    response_type: 'confirmation',
    message,
    data: { deferred_count: deferred, issue_ids: issueIds, warnings, dry_run: DRY_RUN },
    suggestions: ['Type /today to see updated board'],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

// ===========================================
// /add — Manual Quest Addition
// ===========================================
// Creates a new quest in the Daily Quests project
// Expects params: { name, duration } or { name, duration, priority }

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
