const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';
const DRY_RUN = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || 'false') === '1';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const formatDuration = (min) => {
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

const params = $input.first().json.params || {};

try {
  const name = params.name;
  const durationStr = params.duration;

  if (!name || !durationStr) {
    return [{ json: {
      response_type: 'error',
      message: '\u274C [INVALID_INPUT] Usage: /add {name} {duration} (e.g., /add Code Review 1h). Please check input format and try again.',
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Example: /add Code Review 1h', 'Example: /add Bug Fix 30min'],
      awaiting_input: false
    }}];
  }

  // Parse duration string (e.g., '1h', '30min', '1h30min', '90min')
  let durationMin = 0;
  const hMatch = durationStr.match(/(\d+)h/);
  const mMatch = durationStr.match(/(\d+)m(?:in)?/);
  if (hMatch) durationMin += parseInt(hMatch[1]) * 60;
  if (mMatch) durationMin += parseInt(mMatch[1]);
  if (durationMin === 0) {
    // Try plain number as minutes
    const plain = parseInt(durationStr);
    if (!isNaN(plain) && plain > 0) durationMin = plain;
  }

  if (durationMin <= 0) {
    return [{ json: {
      response_type: 'error',
      message: `\u274C [INVALID_INPUT] Invalid duration: '${durationStr}'. Use formats like 1h, 30min, or 1h30min. Please check input format and try again.`,
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Example: 1h, 30min, 1h30min, 90'],
      awaiting_input: false
    }}];
  }

  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const nowStr = new Date().toLocaleTimeString('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit' });

  // Priority mapping: default medium (2)
  const priorityMap = { urgent: 4, high: 3, medium: 2, low: 1, none: 0 };
  const priority = priorityMap[params.priority] ?? 2;
  const priorityName = Object.keys(priorityMap).find(k => priorityMap[k] === priority) || 'medium';

  // Build pulse-meta for the manually added quest (manual type with all schema fields)
  const meta = {
    schema_version: 1,
    routine_type: 'manual',
    routine_days: [new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' }).toLowerCase().slice(0, 3)],
    routine_time: nowStr,
    routine_duration_min: durationMin,
    routine_priority: priorityName,
    routine_mandatory: false,
    routine_active_from: todayStr,
    routine_active_until: todayStr,
    routine_cooldown_days: 0,
    source_project_id: config.daily_quest_project_id,
    source_issue_id: 'manual',
    source_type: 'manual',
    quest_date: todayStr,
    defer_count: 0
  };

  const descriptionHtml = `<pre><code class="language-pulse-meta">${JSON.stringify(meta, null, 2)}</code></pre>`;

  const projId = config.daily_quest_project_id;

  if (DRY_RUN) {
    console.log(`[DRY_RUN] Would create manual quest: "${name}" (${formatDuration(durationMin)})`);
  } else {
    await withRetry(
      () => apiPost(`/projects/${projId}/issues/`, {
        name,
        description_html: descriptionHtml,
        priority,
        state: config.state_todo,
        target_date: todayStr,
        start_date: todayStr
      }),
      'Create manual quest'
    );
  }

  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  return [{ json: {
    response_type: 'confirmation',
    message: `\u2705${dryTag} Quest added: "${name}" (${formatDuration(durationMin)})`,
    data: { name, duration_min: durationMin, priority, dry_run: DRY_RUN },
    suggestions: ['Type /today to see updated board'],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

// ===========================================
// /brief — Milestone Briefing
// ===========================================
// /brief: Top 5 milestones sorted by D-Day (closest deadline first)
// /brief all: All milestones grouped by project

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const target = $input.first().json.target;
const showAll = target === 'all';

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });

  // Fetch all projects
  const projectsRes = await withRetry(() => apiGet('/projects/'), 'List projects');
  const projects = projectsRes.results || projectsRes || [];

  const allMilestones = [];

  for (const project of projects) {
    // Fetch modules (milestones) for each project
    const modulesRes = await withRetry(
      () => apiGet(`/projects/${project.id}/modules/?per_page=100`),
      `List modules for ${project.name}`
    );
    const modules = modulesRes.results || modulesRes || [];

    for (const mod of modules) {
      if (!mod.target_date) continue;

      // Calculate D-Day
      const targetMs = new Date(mod.target_date + 'T00:00:00').getTime();
      const todayMs = new Date(todayStr + 'T00:00:00').getTime();
      const dDays = Math.ceil((targetMs - todayMs) / (24 * 60 * 60 * 1000));

      // Fetch module issues for progress calculation
      let progress = 0;
      try {
        const issuesRes = await withRetry(
          () => apiGet(`/projects/${project.id}/modules/${mod.id}/module-issues/?per_page=100&expand=state`),
          `Module issues for ${mod.name}`
        );
        const issues = issuesRes.results || issuesRes || [];
        const total = issues.length;
        if (total > 0) {
          const completed = issues.filter(i => {
            const issue = i.issue_detail || i;
            const stateName = issue.state_detail?.name || issue.state_name || '';
            return stateName === 'Done';
          }).length;
          progress = Math.round((completed / total) * 100);
        }
      } catch (e) {
        console.log(`[WARN] Could not fetch issues for module ${mod.name}: ${e.message}`);
      }

      allMilestones.push({
        project_name: project.name,
        milestone_name: mod.name,
        progress,
        d_days: dDays,
        target_date: mod.target_date,
        status: mod.status || 'unknown',
      });
    }
  }

  // Sort by D-Day (closest first)
  allMilestones.sort((a, b) => a.d_days - b.d_days);

  if (allMilestones.length === 0) {
    return [{ json: {
      response_type: 'info',
      message: '\u2139\uFE0F No milestones with due dates found across your projects.',
      data: null,
      suggestions: ['Create milestones (modules) in Plane.so with target dates'],
      awaiting_input: false
    }}];
  }

  let message = '';

  if (showAll) {
    // Group by project
    const grouped = {};
    for (const m of allMilestones) {
      if (!grouped[m.project_name]) grouped[m.project_name] = [];
      grouped[m.project_name].push(m);
    }

    message = '\uD83C\uDFAF **All Milestones**\n';
    for (const [projName, milestones] of Object.entries(grouped)) {
      message += `\n**${projName}**\n`;
      for (const m of milestones) {
        const dLabel = m.d_days >= 0 ? `D-${m.d_days}` : `D+${Math.abs(m.d_days)} (overdue)`;
        message += `  \uD83C\uDFAF ${m.milestone_name}: ${m.progress}% (${dLabel})\n`;
      }
    }
  } else {
    // Top 5
    const top5 = allMilestones.slice(0, 5);
    message = '\uD83C\uDFAF **Top 5 Milestones**\n\n';
    for (const m of top5) {
      const dLabel = m.d_days >= 0 ? `D-${m.d_days}` : `D+${Math.abs(m.d_days)} (overdue)`;
      message += `\uD83C\uDFAF ${m.project_name} \u2014 ${m.milestone_name}: ${m.progress}% (${dLabel})\n`;
    }
  }

  return [{ json: {
    response_type: 'info',
    message,
    data: { milestones: showAll ? allMilestones : allMilestones.slice(0, 5), total: allMilestones.length },
    suggestions: showAll ? [] : ['Use /brief all to see all milestones'],
    awaiting_input: false
  }}];
