// /stats — N-Day Statistics
// ===========================================
// Shows quest completion statistics for past N days.
// Default N=7 if not specified.

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
