};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};


const fetchAllIssues = async (path) => {
  let allItems = [];
  let cursor = undefined;
  let hasMore = true;
  while (hasMore) {
    const url = cursor ? `${path}&cursor=${cursor}` : path;
    const res = await withRetry(() => apiGet(url), 'Fetch issues page');
    const data = res.results || res || [];
    allItems = allItems.concat(Array.isArray(data) ? data : []);
    hasMore = res.next_page_results === true;
    cursor = res.next_cursor || undefined;
    if (!hasMore || !cursor) break;
  }
  return allItems;
};

const params = $input.first().json.params || {};

try {
  const days = parseInt(params.days) || 7;
  if (days < 1 || days > 90) {
    return [{ json: {
      response_type: 'error',
      message: '\u274C [INVALID_INPUT] Days must be between 1 and 90. Please check input format and try again.',
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Example: /stats 7, /stats 30'],
      awaiting_input: false
    }}];
  }

  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const projId = config.daily_quest_project_id;

  // Calculate date range
  const dates = [];
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date();
    d.setDate(d.getDate() - i);
    dates.push(d.toLocaleDateString('en-CA', { timeZone: tz }));
  }

  // Fetch all issues in daily quest project (paginated)
  const allIssues = await fetchAllIssues(`/projects/${projId}/issues/?per_page=100&expand=labels,state`);

  // Build daily breakdown
  const dailyStats = {};
  for (const date of dates) {
    dailyStats[date] = { total: 0, completed: 0, deferred: 0, canceled: 0 };
  }

  for (const issue of allIssues) {
    const td = issue.target_date;
    if (!td || !dailyStats[td]) continue;
    dailyStats[td].total++;
    const state = issue.state_detail?.name || '';
    if (state === 'Done') dailyStats[td].completed++;
    else if (state === 'Deferred') dailyStats[td].deferred++;
    else if (state === 'Canceled') dailyStats[td].canceled++;
  }

  // Calculate totals
  let totalQuests = 0, totalCompleted = 0, totalDeferred = 0, totalCanceled = 0;
  let bestDay = null, bestRate = -1, worstDay = null, worstRate = 101;

  for (const date of dates) {
    const s = dailyStats[date];
    totalQuests += s.total;
    totalCompleted += s.completed;
    totalDeferred += s.deferred;
    totalCanceled += s.canceled;

    if (s.total > 0) {
      const rate = Math.round((s.completed / s.total) * 100);
      if (rate > bestRate) { bestRate = rate; bestDay = date; }
      if (rate < worstRate) { worstRate = rate; worstDay = date; }
    }
  }

  const completionRate = totalQuests > 0 ? Math.round((totalCompleted / totalQuests) * 100) : 0;
  const deferralRate = totalQuests > 0 ? Math.round((totalDeferred / totalQuests) * 100) : 0;

  // Format message
  let message = `\uD83D\uDCCA **${days}-Day Statistics**\n\n`;
  message += `**Summary**\n`;
  message += `  Total quests: ${totalQuests}\n`;
  message += `  Completed: ${totalCompleted} (${completionRate}%)\n`;
  message += `  Deferred: ${totalDeferred} (${deferralRate}%)\n`;
  message += `  Canceled: ${totalCanceled}\n\n`;

  if (bestDay) {
    const bDayName = new Date(bestDay + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    message += `  \uD83C\uDFC6 Best: ${bestDay} (${bDayName}) \u2014 ${bestRate}%\n`;
  }
  if (worstDay && worstDay !== bestDay) {
    const wDayName = new Date(worstDay + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    message += `  \uD83D\uDCC9 Worst: ${worstDay} (${wDayName}) \u2014 ${worstRate}%\n`;
  }

  message += `\n**Daily Breakdown**\n`;
  for (const date of dates) {
    const s = dailyStats[date];
    const dayName = new Date(date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    const rate = s.total > 0 ? Math.round((s.completed / s.total) * 100) : 0;
    const bar = s.total > 0 ? ('\u2588'.repeat(Math.round(rate / 10)) + '\u2591'.repeat(10 - Math.round(rate / 10))) : '\u2591'.repeat(10);
    message += `  ${date} (${dayName}) ${bar} ${s.completed}/${s.total} (${rate}%)\n`;
  }

  return [{ json: {
    response_type: 'info',
    message,
    data: { days, total_quests: totalQuests, completed: totalCompleted, deferred: totalDeferred, canceled: totalCanceled, completion_rate: completionRate, daily: dailyStats },
    suggestions: [],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

