  return res.json();
};

const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&apos;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

try {
  const projId = config.daily_quest_project_id;

  // Fetch all deferred issues
  const result = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&state=${config.state_deferred}`),
    'Fetch deferred quests'
  );
  const deferred = result.results || result || [];

  if (deferred.length === 0) {
    return [{ json: {
      response_type: 'info',
      message: '\u2139\uFE0F No deferred quests found. All clear!',
      data: null,
      suggestions: ['Try /today to view your quest board'],
      awaiting_input: false
    }}];
  }

  // Resolve source_project_id -> project name (cached)
  const projectNameCache = {};
  const resolveProjectName = async (projectId) => {
    if (!projectId || projectId === 'unknown') return 'unknown';
    if (projectNameCache[projectId]) return projectNameCache[projectId];
    try {
      const proj = await withRetry(() => apiGet(`/projects/${projectId}/`), `Resolve project ${projectId}`);
      projectNameCache[projectId] = proj.name || projectId;
    } catch (e) {
      console.log(`[WARN] Could not resolve project ${projectId}: ${e.message}`);
      projectNameCache[projectId] = projectId;
    }
    return projectNameCache[projectId];
  };

  let message = `\u23F8\uFE0F **Deferred Quests** (${deferred.length})\n\n`;

  for (const issue of deferred) {
    const meta = extractMeta(issue.description_html);
    const deferCount = meta?.defer_count || 0;
    const sourceProjectId = meta?.source_project_id || 'unknown';
    const sourceProjectName = await resolveProjectName(sourceProjectId);
    const originalDate = issue.target_date || 'unknown';

    let line = `  \u23F8\uFE0F ${issue.name}`;
    if (sourceProjectName !== 'unknown') line += ` [${sourceProjectName}]`;
    if (originalDate !== 'unknown') line += ` (${originalDate})`;
    line += ` \u2014 deferred x${deferCount}`;

    if (deferCount >= 5) {
      line += `\n    \u26A0\uFE0F (deferred x${deferCount} \u2014 consider removing)`;
    }

    message += line + '\n';
  }

  message += '\n_Use /restore to bring quests back, or /cancel to remove them._';

  return [{ json: {
    response_type: 'info',
    message,
    data: { count: deferred.length, quests: deferred.map(d => ({ id: d.id, name: d.name, defer_count: extractMeta(d.description_html)?.defer_count || 0 })) },
    suggestions: ['/restore', '/cancel'],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

