      if (i === MAX_RETRIES) {
        const isTimeout = e.code === 'ETIMEDOUT' || e.code === 'ECONNABORTED' || e.message?.includes('timeout');
        const errorCode = isTimeout ? 'PLANE_API_TIMEOUT' : 'PLANE_API_ERROR';
        const err = new Error(`[${errorCode}] ${ctx}: ${e.message}`);
        err.errorCode = errorCode;
        throw err;
      }
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&apos;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

const PRIORITY_EMOJI = { urgent: '\uD83D\uDD34', high: '\uD83D\uDFE0', medium: '\uD83D\uDFE1', low: '\uD83D\uDFE2' };
const validRoutineTypes = ['daily', 'weekly', 'custom'];
const validPriorities = ['urgent', 'high', 'medium', 'low'];

try {
  // Calculate tomorrow's date and day-of-week
  const tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  const tomorrowStr = tomorrow.toLocaleDateString('en-CA', { timeZone: tz });
  const dayNames = ['sun', 'mon', 'tue', 'wed', 'thu', 'fri', 'sat'];
  const tomorrowDay = dayNames[new Date(tomorrow.toLocaleString('en-US', { timeZone: tz })).getDay()];
  const tomorrowDayFull = tomorrow.toLocaleDateString('en-US', { timeZone: tz, weekday: 'long' });

  // Fetch recent quests for cooldown check
  const recentRes = await withRetry(
    () => apiGet(`/projects/${config.daily_quest_project_id}/issues/?per_page=100&expand=labels,state`),
    'Fetch recent quests for cooldown'
  );
  const recentIssues = recentRes.results || recentRes || [];
  const lastQuestDateBySource = new Map();
  for (const ri of recentIssues) {
    if (!ri.target_date) continue;
    const srcMatch = (ri.description_html || '').match(/"source_issue_id"\s*:\s*"([^"]+)"/);
    if (srcMatch) {
      const existing = lastQuestDateBySource.get(srcMatch[1]);
      if (!existing || ri.target_date > existing) {
        lastQuestDateBySource.set(srcMatch[1], ri.target_date);
      }
    }
  }

  // Fetch all projects
  const projectsRes = await withRetry(() => apiGet('/projects/'), 'List projects');
  const projects = projectsRes.results || projectsRes || [];

  const expectedQuests = [];
  const warnings = [];

  for (const project of projects) {
    if (project.id === config.daily_quest_project_id) continue;

    const issuesRes = await withRetry(
      () => apiGet(`/projects/${project.id}/issues/?per_page=100&expand=labels,state`),
      `Fetch issues for ${project.identifier || project.name}`
    );
    const issues = issuesRes.results || issuesRes || [];

    for (const issue of issues) {
      const labels = issue.label_detail || issue.labels || [];
      const labelNames = labels.map((l) => (typeof l === 'string' ? l : l.name || ''));

      const hasExactLabel = labelNames.includes('daily-routine');
      const hasNearMatch = !hasExactLabel && labelNames.some((n) =>
        n.toLowerCase().includes('daily') && n.toLowerCase().includes('routine')
      );

      if (hasNearMatch) {
        const nearLabel = labelNames.find((n) => n.toLowerCase().includes('daily') && n.toLowerCase().includes('routine'));
        warnings.push(`\u26A0\uFE0F [LABEL_MISMATCH] Issue '${issue.name}' has label '${nearLabel}' \u2014 did you mean 'daily-routine'?`);
      }

      if (!hasExactLabel) continue;

      // Parse pulse-meta
      const meta = extractMeta(issue.description_html);
      if (!meta) {
        warnings.push(`\u26A0\uFE0F [INVALID_ROUTINE_META] Routine '${issue.name}' \u2014 no pulse-meta block`);
        continue;
      }

      // Validate
      const metaErrors = [];
      if (meta.schema_version !== 1) metaErrors.push('invalid schema_version');
      if (!meta.routine_days || !Array.isArray(meta.routine_days) || meta.routine_days.length === 0) metaErrors.push('missing/invalid routine_days');
      if (!meta.routine_time) metaErrors.push('missing routine_time');
      if (meta.routine_type && !validRoutineTypes.includes(meta.routine_type)) metaErrors.push(`invalid routine_type: ${meta.routine_type}`);
      if (meta.routine_priority && !validPriorities.includes(meta.routine_priority)) metaErrors.push(`invalid routine_priority: ${meta.routine_priority}`);
      if (metaErrors.length > 0) {
        warnings.push(`\u26A0\uFE0F [INVALID_ROUTINE_META] Routine '${issue.name}' \u2014 ${metaErrors.join(', ')}`);
        continue;
      }

      // Check schedule for tomorrow
      if (!meta.routine_days.includes(tomorrowDay)) continue;
      if (meta.routine_active_from && meta.routine_active_from > tomorrowStr) continue;
      if (meta.routine_active_until && meta.routine_active_until < tomorrowStr) continue;

      // Check cooldown_days
      if (meta.routine_cooldown_days && meta.routine_cooldown_days > 0) {
        const lastDate = lastQuestDateBySource.get(issue.id);
        if (lastDate) {
          const lastMs = new Date(lastDate + 'T00:00:00').getTime();
          const tmrMs = new Date(tomorrowStr + 'T00:00:00').getTime();
          const daysSince = Math.floor((tmrMs - lastMs) / (24 * 60 * 60 * 1000));
          if (daysSince < meta.routine_cooldown_days) continue;
        }
      }

      const pEmoji = PRIORITY_EMOJI[meta.routine_priority] || '\uD83D\uDFE1';
      expectedQuests.push({
        name: issue.name,
        project: project.name,
        time: meta.routine_time,
        duration_min: meta.routine_duration_min,
        priority: meta.routine_priority || 'medium',
        priority_emoji: pEmoji,
      });
    }
  }

  // Sort by time
  expectedQuests.sort((a, b) => (a.time || '').localeCompare(b.time || ''));

  const formatDuration = (min) => {
    if (!min) return '';
    if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
    return `${min}min`;
  };

  let message = `\uD83D\uDCCB ${tomorrowStr} (${tomorrowDayFull}) Preview \u2014 Expected Quests\n\n`;

  if (expectedQuests.length === 0) {
    message += '_No routines scheduled for tomorrow._\n';
  } else {
    for (const q of expectedQuests) {
      const dur = q.duration_min ? ` (${formatDuration(q.duration_min)})` : '';
      message += `  ${q.priority_emoji} ${q.name} \u2014 ${q.time}${dur} [${q.project}]\n`;
    }
    message += `\n_Total: ${expectedQuests.length} quest(s) expected_\n`;
  }

  if (warnings.length > 0) {
    message += '\n**Warnings**\n';
    for (const w of warnings) {
      message += `${w}\n`;
    }
  }

  return [{ json: {
    response_type: 'info',
    message,
    data: { date: tomorrowStr, day: tomorrowDayFull, quests: expectedQuests, warnings },
    suggestions: [],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

