    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const fetchAllIssues = async (path) => {
  let allItems = [];
  let cursor = undefined;
  let hasMore = true;
  while (hasMore) {
    const url = cursor ? `${path}&cursor=${cursor}` : path;
    const res = await withRetry(() => apiGet(url), 'Fetch issues page');
    const data = res.results || res || [];
    allItems = allItems.concat(Array.isArray(data) ? data : []);
    hasMore = res.next_page_results === true;
    cursor = res.next_cursor || undefined;
    if (!hasMore || !cursor) break;
  }
  return allItems;
};

try {
  const now = new Date();
  const todayStr = now.toLocaleDateString('en-CA', { timeZone: tz });
  const projId = config.daily_quest_project_id;

  // Calculate Monday of current week
  const todayLocal = new Date(now.toLocaleString('en-US', { timeZone: tz }));
  const dayOfWeek = todayLocal.getDay(); // 0=Sun, 1=Mon, ...
  const diffToMonday = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
  const monday = new Date(todayLocal);
  monday.setDate(monday.getDate() - diffToMonday);

  // Build date range (Monday through today)
  const daysSoFar = dayOfWeek === 0 ? 6 : dayOfWeek - 1; // Mon=0 .. Sun=6
  const weekDates = [];
  for (let i = 0; i <= daysSoFar; i++) {
    const d = new Date(monday);
    d.setDate(d.getDate() + i);
    weekDates.push(d.toLocaleDateString('en-CA', { timeZone: tz }));
  }

  // Fetch all issues (paginated)
  const allIssues = await fetchAllIssues(`/projects/${projId}/issues/?per_page=100&expand=labels,state`);

  // Build daily stats
  const dailyStats = {};
  for (const date of weekDates) {
    dailyStats[date] = { total: 0, completed: 0, deferred: 0, canceled: 0 };
  }

  for (const issue of allIssues) {
    const td = issue.target_date;
    if (!td || !dailyStats[td]) continue;
    dailyStats[td].total++;
    const state = issue.state_detail?.name || '';
    if (state === 'Done') dailyStats[td].completed++;
    else if (state === 'Deferred') dailyStats[td].deferred++;
    else if (state === 'Canceled') dailyStats[td].canceled++;
  }

  // Calculate totals
  let totalQuests = 0, totalCompleted = 0, totalDeferred = 0, totalCanceled = 0;
  let bestDay = null, bestRate = -1, worstDay = null, worstRate = 101;

  for (const date of weekDates) {
    const s = dailyStats[date];
    totalQuests += s.total;
    totalCompleted += s.completed;
    totalDeferred += s.deferred;
    totalCanceled += s.canceled;

    if (s.total > 0) {
      const rate = Math.round((s.completed / s.total) * 100);
      if (rate > bestRate) { bestRate = rate; bestDay = date; }
      if (rate < worstRate) { worstRate = rate; worstDay = date; }
    }
  }

  const avgRate = totalQuests > 0 ? Math.round((totalCompleted / totalQuests) * 100) : 0;
  const avgDaily = weekDates.length > 0 ? Math.round(totalQuests / weekDates.length * 10) / 10 : 0;

  const mondayStr = weekDates[0];
  const endStr = weekDates[weekDates.length - 1];

  let message = `\uD83D\uDCCA **Weekly Summary** (${mondayStr} \u2014 ${endStr})\n\n`;

  message += `**Totals**\n`;
  message += `  Total quests: ${totalQuests} (avg ${avgDaily}/day)\n`;
  message += `  Completed: ${totalCompleted} (${avgRate}%)\n`;
  message += `  Deferred: ${totalDeferred}\n`;
  message += `  Canceled: ${totalCanceled}\n\n`;

  if (bestDay) {
    const bName = new Date(bestDay + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    message += `  \uD83C\uDFC6 Most productive: ${bestDay} (${bName}) \u2014 ${bestRate}%\n`;
  }
  if (worstDay && worstDay !== bestDay) {
    const wName = new Date(worstDay + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    message += `  \uD83D\uDCC9 Least productive: ${worstDay} (${wName}) \u2014 ${worstRate}%\n`;
  }

  message += `\n**Day-by-Day**\n`;
  for (const date of weekDates) {
    const s = dailyStats[date];
    const dayName = new Date(date + 'T12:00:00').toLocaleDateString('en-US', { weekday: 'short' });
    const rate = s.total > 0 ? Math.round((s.completed / s.total) * 100) : 0;
    const bar = s.total > 0 ? ('\u2588'.repeat(Math.round(rate / 10)) + '\u2591'.repeat(10 - Math.round(rate / 10))) : '\u2591'.repeat(10);
    message += `  ${date} (${dayName}) ${bar} ${s.completed}/${s.total} (${rate}%)\n`;
  }

  return [{ json: {
    response_type: 'info',
    message,
    data: { week_start: mondayStr, week_end: endStr, total_quests: totalQuests, completed: totalCompleted, deferred: totalDeferred, canceled: totalCanceled, avg_rate: avgRate, daily: dailyStats },
    suggestions: [],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

// Unimplemented command handler
const action = $input.first().json.action || 'unknown';
return [{
  json: {
    response_type: 'info',
    message: `\u2139\uFE0F Command /${action} is not yet implemented. It will be available in a future update.`,
    data: { action },
    suggestions: ['Type /help for available commands', 'Try /today to view your quest board'],
    awaiting_input: false,
  }
}];

// ===========================================
// /classify — Natural Language Intent Classification
// ===========================================
// Uses DeepSeek to classify a natural language message into a quest command.
// Falls back to DEGRADED_MODE when LLM is unavailable.

const config = {
  deepseek_api_key: $env.PULSE_DEEPSEEK_API_KEY,
  deepseek_base_url: $env.PULSE_DEEPSEEK_BASE_URL || 'https://api.deepseek.com/v1',
  deepseek_model: $env.PULSE_DEEPSEEK_MODEL || 'deepseek-chat',
};

const params = $input.first().json.params || {};
const message = params.message || '';
const activeSession = params.active_session || false;
const sessionAction = params.session_action || null;

if (!message) {
  return [{ json: {
    response_type: 'error',
    message: '\u274C [INVALID_INPUT] No message provided for classification. Please check input format and try again.',
    data: { error_code: 'INVALID_INPUT' },
