    data: { error_code: 'DEGRADED_MODE', fallback: 'slash_commands' },
    suggestions: ['Type /help for available commands'],
    awaiting_input: false
  }}];
}

const SYSTEM_PROMPT = `# W2 Intent Classification — DeepSeek Disambiguation

## Role
You are a command intent classifier for the pulse quest management system. Analyze the user's natural language input and determine which quest command they intend to execute.

## Available Commands
| Action | Description |
|--------|-------------|
| today | View today's quest board |
| complete | Mark quests as done |
| cancel | Cancel quests |
| defer | Defer quests to later |
| restore | Restore deferred quests |
| edit | Edit quest time or priority |
| add | Add a new manual quest |
| regen | Regenerate today's quests |
| brief | View milestone briefings |
| stats | View N-day statistics |
| deferred | View deferred quests |
| preview | Preview tomorrow's quests |
| weekly | Weekly summary report |
| help | Show command reference |
| create_routine | Create a new routine |

## Constraints
- If the intent is clear, set confidence to "high".
- If ambiguous (2-3 possible commands), set confidence to "low" and provide alternatives.
- If completely unrelated, set action to "unknown".
- Ambiguous words like "done", "skip", "next" — check active_session context.
- Extract any parameters: quest numbers (target), duration, time, name, priority.

## Output Format
Respond with valid JSON:
{
  "action": "string",
  "confidence": "high|low",
  "target": "string|null",
  "params": {},
  "alternatives": [{"action": "string", "reasoning": "string"}],
  "reasoning": "string"
}`;

const userPrompt = JSON.stringify({
  user_message: message,
  active_session: activeSession,
  session_action: sessionAction,
});

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const BACKOFF = [1000, 2000, 4000];
const MAX_RETRIES = 3;
const TIMEOUT_MS = 15000;

try {
  let result = null;

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const controller = new AbortController();
      const tid = setTimeout(() => controller.abort(), TIMEOUT_MS);

      const response = await fetch(`${config.deepseek_base_url}/chat/completions`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${config.deepseek_api_key}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: config.deepseek_model,
          messages: [
            { role: 'system', content: SYSTEM_PROMPT },
            { role: 'user', content: userPrompt },
          ],
          temperature: 0.3,
          max_tokens: 512,
          response_format: { type: 'json_object' },
        }),
        signal: controller.signal,
      });

      clearTimeout(tid);

      if (!response.ok) throw new Error(`HTTP ${response.status}`);

      const data = await response.json();
      result = data.choices?.[0]?.message?.content;
      break;
    } catch (e) {
      console.log(`[RETRY] classify attempt ${attempt + 1}/${MAX_RETRIES}: ${e.message}`);
      if (attempt === MAX_RETRIES - 1) throw e;
      await sleep(BACKOFF[attempt]);
    }
  }

  const parsed = JSON.parse(result);

  // Validate required fields
  if (!parsed.action || !parsed.confidence) {
    throw new Error('Missing required fields: action, confidence');
  }

  // High confidence: return classified intent directly
  if (parsed.confidence === 'high') {
    return [{ json: {
      response_type: 'classification',
      message: `Intent classified: /${parsed.action}`,
      data: {
        action: parsed.action,
        confidence: parsed.confidence,
        target: parsed.target || null,
        params: parsed.params || {},
        reasoning: parsed.reasoning || '',
      },
      suggestions: [],
      awaiting_input: false,
    }}];
  }

  // Low confidence: return options for clarification
  const options = [
    `/${parsed.action} — ${parsed.reasoning}`,
    ...(parsed.alternatives || []).map(a => `/${a.action} — ${a.reasoning}`)
  ];

  return [{ json: {
    response_type: 'classification',
    message: `I'm not sure what you mean. Did you want to:\n${options.map((o, i) => `${i + 1}. ${o}`).join('\n')}`,
    data: {
      action: parsed.action,
      confidence: parsed.confidence,
      target: parsed.target || null,
      params: parsed.params || {},
      alternatives: parsed.alternatives || [],
      reasoning: parsed.reasoning || '',
    },
    suggestions: ['Please choose an option or rephrase your request'],
    awaiting_input: true,
  }}];

} catch (e) {
  console.log(`[ERROR] classify failed: ${e.message}`);
  return [{ json: {
    response_type: 'error',
    message: '\u26A0\uFE0F [DEGRADED_MODE] Natural language processing unavailable. Please use slash commands (type /help for list).',
    data: { error_code: 'DEGRADED_MODE', fallback: 'slash_commands' },
    suggestions: ['Type /help for available commands'],
    awaiting_input: false
  }}];
}

// ===========================================
// /create_routine — Natural Language Routine Creation
// ===========================================
// Creates a new routine in a Plane.so project from extracted NL fields.
// Uses DeepSeek to parse natural language into routine metadata.
// Follows confirmation flow: extract → confirm → create.

const planeConfig = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
  state_todo: $env.PULSE_STATE_TODO_ID,
  label_daily_routine: $env.PULSE_LABEL_DAILY_ROUTINE_ID,
};

const deepseekConfig = {
  api_key: $env.PULSE_DEEPSEEK_API_KEY,
  base_url: $env.PULSE_DEEPSEEK_BASE_URL || 'https://api.deepseek.com/v1',
  model: $env.PULSE_DEEPSEEK_MODEL || 'deepseek-chat',
};

const basePath = `${planeConfig.base_url}/api/v1/workspaces/${planeConfig.workspace_slug}`;
const headers = { 'X-API-Key': planeConfig.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';
const DRY_RUN = ($env.PULSE_DRY_RUN || 'false').toLowerCase() === 'true' || ($env.PULSE_DRY_RUN || 'false') === '1';

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) { const err = new Error(`[PLANE_API_ERROR] ${ctx}: ${e.message}`); err.errorCode = 'PLANE_API_ERROR'; throw err; }
      await sleep(RETRY_MS);
    }
  }
};

const apiPost = async (path, body) => {
  const res = await fetch(`${basePath}${path}`, { method: 'POST', headers, body: JSON.stringify(body) });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

const formatDuration = (min) => {
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

const params = $input.first().json.params || {};
const target = $input.first().json.target || null;

// --- Phase Detection ---
// Phase 1: Extract fields from NL (or receive pre-extracted fields)
// Phase 2: User confirmed → create the routine
// Phase 3 (optional): User confirms immediate quest addition

try {
  // Phase 2: User confirmed routine creation
  if (target === 'confirm') {
    const name = params.routine_name;
    const time = params.routine_time;
    const durationMin = parseInt(params.routine_duration_min);
    const priority = params.routine_priority || 'medium';
    const days = params.routine_days || ['mon', 'tue', 'wed', 'thu', 'fri'];
    const mandatory = params.routine_mandatory === true || params.routine_mandatory === 'true';
    const projectId = params.target_project_id || planeConfig.daily_quest_project_id;
    const addToday = params.add_today === true || params.add_today === 'true';

    if (!name || !time || !durationMin) {
      return [{ json: {
        response_type: 'error',
        message: '\u274C [INVALID_INPUT] Missing required fields: routine_name, routine_time, routine_duration_min. Please check input format and try again.',
        data: { error_code: 'INVALID_INPUT' },
        suggestions: ['Provide all required fields and try again'],
        awaiting_input: false
      }}];
    }

    const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
    const priorityMap = { urgent: 4, high: 3, medium: 2, low: 1, none: 0 };
    const priorityNum = priorityMap[priority] ?? 2;

    const meta = {
      schema_version: 1,
      routine_type: 'daily',
      routine_days: days,
      routine_time: time,
      routine_duration_min: durationMin,
      routine_priority: priority,
      routine_mandatory: mandatory,
      routine_active_from: todayStr,
      routine_active_until: null,
      routine_cooldown_days: 0,
    };

    const descriptionHtml = `<pre><code class="language-pulse-meta">${JSON.stringify(meta, null, 2)}</code></pre>`;

    if (DRY_RUN) {
      console.log(`[DRY_RUN] Would create routine: "${name}" (${formatDuration(durationMin)} at ${time})`);
      return [{ json: {
        response_type: 'confirmation',
        message: `\u2705 [DRY_RUN] Would create routine: "${name}" — ${time} (${formatDuration(durationMin)}) [${priority}] on ${days.join(', ')}`,
        data: { dry_run: true },
        suggestions: [],
        awaiting_input: false
      }}];
    }

    // Create the routine issue in the target project
    const issue = await withRetry(
      () => apiPost(`/projects/${projectId}/issues/`, {
        name,
        description_html: descriptionHtml,
        priority: priorityNum,
        labels: planeConfig.label_daily_routine ? [planeConfig.label_daily_routine] : [],
      }),
      'Create routine'
    );

    let response = `\u2705 Routine created: "${name}" — ${time} (${formatDuration(durationMin)}) [${priority}] on ${days.join(', ')}`;

    // If user wants to add to today's quests immediately
    if (addToday) {
      const dayOfWeek = new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' }).toLowerCase().slice(0, 3);
      if (days.includes(dayOfWeek)) {
        const questMeta = {
          ...meta,
          source_project_id: projectId,
          source_issue_id: issue.id,
          source_type: 'routine',
          quest_date: todayStr,
          defer_count: 0,
        };
        const questDescHtml = `<pre><code class="language-pulse-meta">${JSON.stringify(questMeta, null, 2)}</code></pre>`;

        await withRetry(
          () => apiPost(`/projects/${planeConfig.daily_quest_project_id}/issues/`, {
            name,
            description_html: questDescHtml,
            priority: priorityNum,
            state: planeConfig.state_todo,
            target_date: todayStr,
            start_date: todayStr,
          }),
          'Create today quest from routine'
        );
        response += '\nAlso added to today\'s quest board!';
      } else {
        response += `\nNote: Today is not in the routine schedule (${days.join(', ')}), so it was not added to today's board.`;
      }
    }

    return [{ json: {
      response_type: 'confirmation',
      message: response,
      data: { routine_id: issue.id },
      suggestions: addToday ? ['/today to see updated board'] : ['Would you like to add this to today\'s quests as well?'],
      awaiting_input: !addToday
    }}];
  }

  // Phase 1: Extract routine fields from natural language
  const message = params.message || '';

  if (!message) {
    return [{ json: {
      response_type: 'error',
      message: '\u274C [INVALID_INPUT] Please describe the routine you want to create (e.g., "daily coding routine at 8pm for 1 hour, high priority, weekdays only"). Please check input format and try again.',
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Example: "daily coding at 8pm for 1h, high priority, weekdays"'],
      awaiting_input: false
    }}];
  }

  // Check DeepSeek availability
  if (!deepseekConfig.api_key) {
    return [{ json: {
      response_type: 'error',
      message: '\u26A0\uFE0F [DEGRADED_MODE] Natural language routine creation requires AI. Please use Plane.so directly to create routines.',
      data: { error_code: 'DEGRADED_MODE' },
      suggestions: ['Create routines directly in Plane.so with the daily-routine label'],
      awaiting_input: false
    }}];
  }

  const SYSTEM_PROMPT = `# Routine Creation Parser

## Role
Extract routine details from the user's natural language description.

## Fields to Extract
- routine_name (string, required): Name/title of the routine
- routine_time (string "HH:MM" 24h, required): Scheduled time
- routine_duration_min (integer 1-480, required): Duration in minutes
- routine_priority (string: "urgent"|"high"|"medium"|"low", default "medium")
- routine_days (array of: "mon"|"tue"|"wed"|"thu"|"fri"|"sat"|"sun", default weekdays)
- routine_mandatory (boolean, default false)
- target_project_id (string, optional — use default if not specified)

## Constraints
- If a field is missing or ambiguous, set it to null and add a question to the "missing" array.
- Time must be in 24-hour format (convert "8pm" to "20:00").
- "Weekdays" = ["mon","tue","wed","thu","fri"], "everyday" = all 7 days, "weekends" = ["sat","sun"].
- All output in English.

## Output Format
{
  "routine_name": "string|null",
  "routine_time": "HH:MM|null",
  "routine_duration_min": number|null,
  "routine_priority": "string",
  "routine_days": ["mon",...],
  "routine_mandatory": false,
  "missing": ["What time should this routine be scheduled?"],
  "complete": true|false
}`;

  const TIMEOUT_MS = 15000;
  const BACKOFF = [1000, 2000, 4000];
  let result = null;

  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const controller = new AbortController();
      const tid = setTimeout(() => controller.abort(), TIMEOUT_MS);

      const response = await fetch(`${deepseekConfig.base_url}/chat/completions`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${deepseekConfig.api_key}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model: deepseekConfig.model,
          messages: [
            { role: 'system', content: SYSTEM_PROMPT },
            { role: 'user', content: message },
          ],
          temperature: 0.3,
          max_tokens: 512,
          response_format: { type: 'json_object' },
        }),
        signal: controller.signal,
      });

      clearTimeout(tid);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      const data = await response.json();
      result = data.choices?.[0]?.message?.content;
      break;
    } catch (e) {
      console.log(`[RETRY] create_routine parse attempt ${attempt + 1}/${MAX_RETRIES}: ${e.message}`);
      if (attempt === MAX_RETRIES - 1) throw e;
      await sleep(BACKOFF[attempt]);
    }
  }

  const parsed = JSON.parse(result);

  // If any required field is missing, ask clarifying questions
  if (!parsed.complete || (parsed.missing && parsed.missing.length > 0)) {
    const question = parsed.missing?.[0] || 'Could you provide more details about this routine?';
    return [{ json: {
      response_type: 'info',
      message: `I need a bit more information to create this routine:\n\n${question}`,
      data: {
        partial_routine: {
          routine_name: parsed.routine_name,
          routine_time: parsed.routine_time,
          routine_duration_min: parsed.routine_duration_min,
          routine_priority: parsed.routine_priority || 'medium',
          routine_days: parsed.routine_days || ['mon', 'tue', 'wed', 'thu', 'fri'],
          routine_mandatory: parsed.routine_mandatory || false,
        },
        missing_fields: parsed.missing || [],
      },
      suggestions: [],
      awaiting_input: true
    }}];
  }

  // All fields extracted — present summary for confirmation
  const r = parsed;
  const durationDisplay = formatDuration(r.routine_duration_min);
  const daysDisplay = r.routine_days.join(', ');

  const summary = [
    `**Name:** ${r.routine_name}`,
    `**Time:** ${r.routine_time}`,
    `**Duration:** ${durationDisplay}`,
    `**Priority:** ${r.routine_priority || 'medium'}`,
    `**Days:** ${daysDisplay}`,
    `**Mandatory:** ${r.routine_mandatory ? 'Yes' : 'No'}`,
  ].join('\n');

  return [{ json: {
    response_type: 'info',
    message: `Here's the routine I'll create:\n\n${summary}\n\nShall I go ahead and create it? (yes/no)`,
    data: {
      parsed_routine: {
        routine_name: r.routine_name,
        routine_time: r.routine_time,
        routine_duration_min: r.routine_duration_min,
        routine_priority: r.routine_priority || 'medium',
        routine_days: r.routine_days || ['mon', 'tue', 'wed', 'thu', 'fri'],
        routine_mandatory: r.routine_mandatory || false,
      },
    },
    suggestions: ['Confirm with "yes" to create, or "no" to cancel'],
    awaiting_input: true
  }}];

} catch (e) {
