const updateMetaInHtml = (html, updates) => {
  if (!html) return html;
  const meta = extractMeta(html);
  if (!meta) return html;
  const updated = { ...meta, ...updates };
  const jsonStr = JSON.stringify(updated, null, 2);
  let result = html.replace(/<pre><code\s+class="language-pulse-meta">[\s\S]*?<\/code><\/pre>/, `<pre><code class="language-pulse-meta">${jsonStr}</code></pre>`);
  if (result !== html) return result;
  result = html.replace(/<pre><code>[\s\S]*?<\/code><\/pre>/, `<pre><code class="language-pulse-meta">${jsonStr}</code></pre>`);
  if (result !== html) return result;
  result = html.replace(/```pulse-meta\s*\n[\s\S]*?\n\s*```/, `\`\`\`pulse-meta\n${jsonStr}\n\`\`\``);
  if (result !== html) return result;
  return html;
};

const PRIORITY_EMOJI = { 4: '\uD83D\uDD34', 3: '\uD83D\uDFE0', 2: '\uD83D\uDFE1', 1: '\uD83D\uDFE2', 0: '\uD83D\uDFE2' };
const PRIORITY_NAME = { 4: 'urgent', 3: 'high', 2: 'medium', 1: 'low', 0: 'none' };
const PRIORITY_VALUE = { 'urgent': 4, 'high': 3, 'medium': 2, 'low': 1, 'none': 0 };
const formatDuration = (min) => {
  if (!min) return '';
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

const target = $input.first().json.target;
const params = $input.first().json.params || {};

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const projId = config.daily_quest_project_id;

  if (!target) {
    // Phase 1: List quests available for editing
    const result = await withRetry(
      () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
      'Fetch today quests'
    );
    const allQuests = result.results || result || [];
    const actionable = allQuests.filter(q => {
      const sn = q.state_detail?.name;
      return sn === 'To-Do' || sn === 'In Progress';
    });

    if (actionable.length === 0) {
      return [{ json: {
        response_type: 'info',
        message: '\u2139\uFE0F No quests available to edit.',
        data: null, suggestions: ['Try /today to view your quest board'], awaiting_input: false
      }}];
    }

    let list = '';
    for (let i = 0; i < actionable.length; i++) {
      const q = actionable[i];
      const pEmoji = PRIORITY_EMOJI[q.priority] || '\uD83D\uDFE1';
      const pName = PRIORITY_NAME[q.priority] || 'medium';
      const meta = extractMeta(q.description_html);
      const time = meta?.routine_time || '--:--';
      const dur = meta?.routine_duration_min ? formatDuration(meta.routine_duration_min) : '';
      list += `${i + 1}. [${pEmoji} ${pName}] ${q.name} \u2014 ${time}${dur ? ` (${dur})` : ''}\n`;
    }

    return [{ json: {
      response_type: 'list',
      message: `Select a quest to edit:\n${list}`,
      data: { quest_ids: actionable.map(q => q.id), count: actionable.length },
      suggestions: ['Enter number(s) (e.g., 1,3 or 1-3):'],
      awaiting_input: true
    }}];
  }

  // Phase 2: Edit selected quest
  const issueIds = target.split(',').map(s => s.trim()).filter(Boolean);
  const nowStr = new Date().toLocaleTimeString('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit' });

  // Validate edit field
  const field = (params.field || '').toLowerCase().trim();
  const value = (params.value || '').trim();

  if (!field || !value) {
    return [{ json: {
      response_type: 'info',
      message: 'What would you like to change? [time/priority]\nExample: "time 21:00" or "priority high"',
      data: { quest_ids: issueIds },
      suggestions: ['time HH:MM', 'priority urgent/high/medium/low'],
      awaiting_input: true
    }}];
  }

  if (field !== 'time' && field !== 'priority') {
    return [{ json: {
      response_type: 'info',
      message: '\u26A0\uFE0F Only time and priority can be edited in this version.',
      data: null,
      suggestions: ['time HH:MM', 'priority urgent/high/medium/low'],
      awaiting_input: false
    }}];
  }

  // Validate value
  if (field === 'time') {
    const timeRegex = /^([01]\d|2[0-3]):([0-5]\d)$/;
    if (!timeRegex.test(value)) {
      return [{ json: {
        response_type: 'error',
        message: `\u274C [INVALID_INPUT] Invalid time format "${value}". Use HH:MM (e.g., 21:00).`,
        data: { error_code: 'INVALID_INPUT' },
        suggestions: ['Example: time 21:00'],
        awaiting_input: false
      }}];
    }
  }

  if (field === 'priority') {
    if (!PRIORITY_VALUE.hasOwnProperty(value)) {
      return [{ json: {
        response_type: 'error',
        message: `\u274C [INVALID_INPUT] Invalid priority "${value}". Use: urgent, high, medium, low, none.`,
        data: { error_code: 'INVALID_INPUT' },
        suggestions: ['Valid: urgent, high, medium, low, none'],
        awaiting_input: false
      }}];
    }
  }

  // Validate issue IDs belong to today's actionable quests
  const todayResult = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today quests for validation'
  );
  const todayQuests = todayResult.results || todayResult || [];
  const actionableIds = new Set(
    todayQuests.filter(q => {
      const sn = q.state_detail?.name;
      return sn === 'To-Do' || sn === 'In Progress';
    }).map(q => q.id)
  );

  const invalidIds = issueIds.filter(id => !actionableIds.has(id));
  if (invalidIds.length > 0) {
    return [{ json: {
      response_type: 'error',
      message: `\u274C [INVALID_INPUT] Issue(s) ${invalidIds.join(', ')} are not in today's actionable quests.`,
      data: { error_code: 'INVALID_INPUT' },
      suggestions: ['Use /edit to see available quests'],
      awaiting_input: false
    }}];
  }

  const results = [];

  for (const issueId of issueIds) {
    const issue = await withRetry(
      () => apiGet(`/projects/${projId}/issues/${issueId}/?expand=labels,state`),
      `Fetch issue ${issueId}`
    );

    if (field === 'time') {
      const updatedHtml = updateMetaInHtml(issue.description_html, { routine_time: value });
      if (DRY_RUN) {
        console.log(`[DRY_RUN] Would edit issue ${issueId}: time \u2192 ${value}`);
      } else {
        await withRetry(
          () => apiPatch(`/projects/${projId}/issues/${issueId}/`, { description_html: updatedHtml }),
          `Edit time on ${issueId}`
        );
        await withRetry(
          () => apiPost(`/projects/${projId}/issues/${issueId}/comments/`, {
            comment_html: `<p>\u270F\uFE0F [${nowStr}] Edited by user: time \u2192 ${value}</p>`
          }),
          `Comment on ${issueId}`
        );
      }
      results.push(`"${issue.name}" \u2014 time changed to ${value}`);
    }

    if (field === 'priority') {
      const newPriority = PRIORITY_VALUE[value];
      if (DRY_RUN) {
        console.log(`[DRY_RUN] Would edit issue ${issueId}: priority \u2192 ${value}`);
      } else {
        await withRetry(
          () => apiPatch(`/projects/${projId}/issues/${issueId}/`, { priority: newPriority }),
          `Edit priority on ${issueId}`
        );
        await withRetry(
          () => apiPost(`/projects/${projId}/issues/${issueId}/comments/`, {
            comment_html: `<p>\u270F\uFE0F [${nowStr}] Edited by user: priority \u2192 ${value}</p>`
          }),
          `Comment on ${issueId}`
        );
      }
      results.push(`"${issue.name}" \u2014 priority changed to ${value}`);
    }
  }

  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  const message = results.map(r => `\u2705${dryTag} Quest updated: ${r}`).join('\n');

  return [{ json: {
    response_type: 'confirmation',
    message,
    data: { edited_count: results.length, issue_ids: issueIds, field, value, dry_run: DRY_RUN },
    suggestions: ['Type /today to see updated board'],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}

