  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

const params = $input.first().json.params || {};

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const projId = config.daily_quest_project_id;

  const confirmed = (params.confirmed || '').toLowerCase().trim();

  if (!confirmed) {
    // Phase 1: Show confirmation prompt
    // Count how many quests would be affected
    const result = await withRetry(
      () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
      'Fetch today quests'
    );
    const quests = result.results || result || [];
    const doneCount = quests.filter(q => q.state_detail?.name === 'Done').length;
    const cancelCount = quests.length - doneCount;

    let message = `\u26A0\uFE0F This will regenerate all quests except completed ones. Are you sure? (yes/no)`;
    if (quests.length > 0) {
      message += `\n\n_${cancelCount} quest${cancelCount !== 1 ? 's' : ''} will be canceled and regenerated. ${doneCount} completed quest${doneCount !== 1 ? 's' : ''} will be kept._`;
    }

    return [{ json: {
      response_type: 'info',
      message,
      data: { total: quests.length, will_cancel: cancelCount, will_keep: doneCount },
      suggestions: ['yes', 'no'],
      awaiting_input: true
    }}];
  }

  if (confirmed === 'no' || confirmed === 'n') {
    return [{ json: {
      response_type: 'info',
      message: '\uD83D\uDC4D Regeneration canceled. Your current quest board is unchanged.',
      data: null,
      suggestions: ['Type /today to see your quest board'],
      awaiting_input: false
    }}];
  }

  if (confirmed !== 'yes' && confirmed !== 'y') {
    return [{ json: {
      response_type: 'info',
      message: '\u26A0\uFE0F Please answer "yes" or "no".',
      data: null,
      suggestions: ['yes', 'no'],
      awaiting_input: true
    }}];
  }

  // Phase 2: Cancel non-done quests, then trigger W1 re-execution
  const result = await withRetry(
    () => apiGet(`/projects/${projId}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today quests for regeneration'
  );
  const quests = result.results || result || [];
  const nonDone = quests.filter(q => q.state_detail?.name !== 'Done');

  let canceledCount = 0;
  const nowStr = new Date().toLocaleTimeString('en-GB', { timeZone: tz, hour: '2-digit', minute: '2-digit' });

  for (const quest of nonDone) {
    if (DRY_RUN) {
      console.log(`[DRY_RUN] Would cancel issue ${quest.id} for regen`);
    } else {
      await withRetry(
        () => apiPatch(`/projects/${projId}/issues/${quest.id}/`, { state: config.state_canceled }),
        `Cancel issue ${quest.id} for regen`
      );
      await withRetry(
        () => apiPost(`/projects/${projId}/issues/${quest.id}/comments/`, {
          comment_html: `<p>\uD83D\uDD04 [${nowStr}] Canceled for quest regeneration</p>`
        }),
        `Comment on ${quest.id}`
      );
    }
    canceledCount++;
  }

  // Now trigger W1 workflow re-execution
  // W1 is a cron workflow — we trigger it by calling its test webhook or production webhook
  // Since W1 runs as cron, we execute steps 1-2 inline (deterministic) here
  // and steps 3-5 if LLM is available
  // For simplicity and reliability, we re-run the same quest generation logic

  // Step 2: Routine Copy — scan routines and create quests for today
  const allProjects = await withRetry(
    () => apiGet('/projects/'),
    'Fetch all projects'
  );
  const projects = allProjects.results || allProjects || [];

  // Get daily-routine label ID
  const labelId = $env.PULSE_LABEL_DAILY_ROUTINE_ID;
  let generated = 0;

  for (const proj of projects) {
    // Skip the daily quest project itself
    if (proj.id === projId) continue;

    try {
      const issuesRes = await withRetry(
        () => apiGet(`/projects/${proj.id}/issues/?per_page=100&expand=labels&label=${labelId}`),
        `Scan routines in ${proj.name}`
      );
      const routines = issuesRes.results || issuesRes || [];

      for (const routine of routines) {
        // Check if routine has the daily-routine label
        const hasLabel = routine.label_details?.some(l => l.id === labelId) || routine.labels?.includes(labelId);
        if (!hasLabel) continue;

        const meta = extractMeta(routine.description_html);
        if (!meta || meta.schema_version !== 1) continue;

        // Check schedule: routine_days
        const dayMap = { 'sun': 0, 'mon': 1, 'tue': 2, 'wed': 3, 'thu': 4, 'fri': 5, 'sat': 6 };
        const todayDow = new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' }).toLowerCase();
        const routineDays = (meta.routine_days || []).map(d => d.toLowerCase());
        if (routineDays.length > 0 && !routineDays.includes(todayDow)) continue;

        // Check active_from / active_until
        if (meta.routine_active_from && todayStr < meta.routine_active_from) continue;
        if (meta.routine_active_until && todayStr > meta.routine_active_until) continue;

        // Check cooldown
        if (meta.routine_cooldown_days && meta.routine_cooldown_days > 0) {
          try {
            const recentRes = await withRetry(
              () => apiGet(`/projects/${projId}/issues/?per_page=5&expand=labels&target_date=${todayStr}`),
              `Check cooldown for ${routine.name}`
            );
            const recent = recentRes.results || recentRes || [];
            const hasDuplicate = recent.some(q => {
              const qMeta = extractMeta(q.description_html);
              return qMeta?.source_issue_id === routine.id;
            });
            if (hasDuplicate) continue;
          } catch (e) {
            console.log(`[WARN] Cooldown check failed: ${e.message}`);
          }
        }

        // Duplicate check: skip if quest already exists for today from this routine
        // (covered by cooldown check above for today's quests)

        // Create quest
        const questMeta = {
          schema_version: 1,
          routine_type: meta.routine_type || 'daily',
          routine_days: meta.routine_days || [],
          routine_time: meta.routine_time || '09:00',
          routine_duration_min: meta.routine_duration_min || 30,
          routine_priority: meta.routine_priority || 'medium',
          routine_mandatory: meta.routine_mandatory || false,
          routine_active_from: meta.routine_active_from,
          routine_active_until: meta.routine_active_until,
          routine_cooldown_days: meta.routine_cooldown_days || 0,
          source_project_id: proj.id,
          source_issue_id: routine.id,
          defer_count: 0
        };

        const priorityMap = { 'urgent': 4, 'high': 3, 'medium': 2, 'low': 1, 'none': 0 };
        const priority = priorityMap[meta.routine_priority] || 2;

        const questBody = {
          name: routine.name,
          description_html: `<pre><code class="language-pulse-meta">${JSON.stringify(questMeta, null, 2)}</code></pre>`,
          priority,
          state: config.state_todo,
          target_date: todayStr,
          start_date: todayStr,
        };

        if (DRY_RUN) {
          console.log(`[DRY_RUN] Would create quest: ${routine.name}`);
        } else {
          await withRetry(
            () => apiPost(`/projects/${projId}/issues/`, questBody),
            `Create quest ${routine.name}`
          );
        }
        generated++;
      }
    } catch (e) {
      console.log(`[WARN] Failed to scan project ${proj.name}: ${e.message}`);
    }
  }

  const dryTag = DRY_RUN ? ' [DRY_RUN]' : '';
  return [{ json: {
    response_type: 'confirmation',
    message: `\u2705${dryTag} Today's quests regenerated! ${canceledCount} quest${canceledCount !== 1 ? 's' : ''} canceled, ${generated} new quest${generated !== 1 ? 's' : ''} generated. Use /today to see the new board.`,
    data: { canceled_count: canceledCount, generated_count: generated, dry_run: DRY_RUN },
    suggestions: ['Type /today to see the new board'],
    awaiting_input: false
  }}];
} catch (e) {
  const code = e.errorCode || 'PLANE_API_ERROR';
  const recovery = code === 'PLANE_API_TIMEOUT'
    ? 'Please check Plane.so service status and try again later.'
    : 'Please check Plane.so API configuration.';
  return [{ json: {
    response_type: 'error',
    message: `\u274C [${code}] ${e.message}. ${recovery}`,
    data: { error_code: code },
    suggestions: ['Check n8n execution logs'],
    awaiting_input: false
  }}];
}
